var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"일주일 뒤, 작전 당일","JPN":"一週間後、作戦当日","ENG":"One week later, Operation day","TWN":"一周後，行動當天","SCN":"一周后，行动当天","DEU":"One week later, Operation day","FRA":"One week later, Operation day"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"샤레이드 ~ 로터스 관리 경계 구역\\n<color=#ffd34c>CSE LV.2</color>","JPN":"シャレード～ロータス管理警戒区域\\n<color=#ffd34c>CSE LV.2</color>","ENG":"[[","TWN":"查雷德～洛德斯管理警戒區域\\n<color=#ffd34c>CSE LV.2</color>","SCN":"查雷德 ~ 洛德斯管理警戒区域\\n<color=#ffd34c>CSE LV.2</color>","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"곧, 작전 구역에 도착합니다.","JPN":"間もなく、作戦区域に到着します。","ENG":"We'll be arriving at the operation zone shortly.","TWN":"即將到達作戰區域。"},"stage":{"bg":"MS_1407","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"현재 좌표로부터 목표 포인트의 좌표까지는 최단 거리로 5km 지점.","JPN":"現在の位置から目標ポイントの座標までは最短距離にして5km。","ENG":"The shortest distance to the target point from current coordinates is 5 km.","TWN":"從當前座標到目標點的座標，最短距離為5公里。"},"stage":{"bg":"MS_1407","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"브리핑대로, 그 지점까지는 저희가 헌신을 다해 두 분을 에스코트하겠습니다.","JPN":"ブリーフィングどおり、該当地点までは私たちが全力でお二人をエスコートいたします。","ENG":"As per the briefing, we will escort you to that point with utmost dedication.","TWN":"根據報告，我們會全力護送兩位到達那個地點。"},"stage":{"bg":"MS_1407","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"고마워요, 로즈 분들.","JPN":"ありがとうございます、ローズのみなさん。","ENG":"Thank you, Roses.","TWN":"謝謝你們，玫瑰們。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"들리세요, 메이시 박사님? 저희 작전 구역에 도착했어요.","JPN":"聞こえますか、メイシ博士？　私たち、作戦区域に到着しました。","ENG":"Can you hear me, Dr. Macy? We've arrived at the operation zone.","TWN":"聽得到嗎？梅西博士？我們已經到達作戰區域了。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"이쪽도 너희 위치를 확인했어, 꼬맹이.","JPN":"こっちからも位置を確認したわ。","ENG":"Got your position on my end too, kid.","TWN":"這邊也確認了你們的位置，小鬼。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"노파심에 한 번 더 말하지만, 일단 작전 자체는 간단해.","JPN":"もう一度言うけど、とりあえず作戦自体は簡単よ。","ENG":"Just to be clear, the operation itself is simple.","TWN":"雖然有些多慮，但我再說一次，作戰本身很簡單。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"관리 경계 구역 특정 좌표에 차원 계면이 손상된 흔적이 있어.","JPN":"管理警戒区域の特定座標に次元界面が損傷した痕跡が残っている。","ENG":"There are traces of dimension surface damage at specific coordinates of the perimeter zone.","TWN":"管理警戒區域的特定座標處有次元介面的損傷痕跡。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"아마도 누군가 이쪽 현실에서 다른 세계로 차원 균열을 발생시킨 흔적이겠지.","JPN":"おそらく誰かがこちらの現実から他の世界に向けて次元の亀裂を発生させたのでしょうね。","ENG":"It's likely caused by someone forcing a dimensional rift between reality here and another world.","TWN":"可能是有人在這個現實中，引發了通往其他世界的次元裂縫的痕跡吧。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"우리 목표는 그 흔적을 역추적하여 좌표를 역산. 다이브를 시도하는 거야.","JPN":"私たちの目標はその痕跡を追跡して座標を逆算し、ダイブを試みること。","ENG":"Our goal is to trace that rift and reverse-calculate the coordinates for a dive.","TWN":"我們的目標是追蹤那些痕跡，反算出座標，然後嘗試躍入。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"그리고 우리가 도와줄 수 있는 건, 그 정도일 거야.","JPN":"今の私たちにできるのは、その程度ね。","ENG":"And this is about all the help we can offer.","TWN":"而我們能幫的，也就只有這些了。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"박사님이 만든 이 우주복…….","JPN":"博士が作ったこの宇宙服……","ENG":"This space suit you made, Doctor...","TWN":"博士製作的這套太空裝……"},"stage":{"bg":"HELI_NORMAL","slots":{"L":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"<color=#ffd34c>싱글 다이빙 슈트</color>라고 하셨죠?","JPN":"<color=#ffd34c>シングルダイビングスーツ</color>でしたっけ？","ENG":"You called it a <color=#ffd34c>Single Diving Suit</color>, right?","TWN":"是叫<color=#ffd34c>單人潛水衣</color>嗎？"},"stage":{"bg":"HELI_NORMAL","slots":{"L":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"정말로 이 슈트만 있으면, 차원 함선 없이 다이브가 가능한 거예요?","JPN":"本当にこのスーツさえあれば、次元艦船なしでダイブできるんですか？","ENG":"Are you sure this suit alone lets us dive without a dimensional ship?","TWN":"真的只要有這套戰鬥服，就能在沒有次元艦船的情況下進行躍入嗎？"},"stage":{"bg":"HELI_NORMAL","slots":{"L":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"걱정할 필요 없어.","JPN":"心配する必要はないわ。","ENG":"No need to worry.","TWN":"不用擔心。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"실제 테스트는 이번이 처음이지만, 이론적으로는 이미 완벽하거든.","JPN":"実践テストは今回が初めてだけど、理論的にはすでに完璧よ。","ENG":"It's the first live test, but theoretically, it's perfect.","TWN":"雖然這是第一次實際測試，但理論上已經完美無缺了。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"이론적으로는……?","JPN":"理論的には……？","ENG":"Theoretically...?","TWN":"理論上是？"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"잘 들으라고, 꼬맹아.","JPN":"よく聞きなさい、ガキ。","ENG":"Listen up, kid.","TWN":"聽好了，小鬼。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"인위적으로 차원 균열을 발생시키는 기술은 이미 통용되고 있는 기술이야.","JPN":"人為的に次元の亀裂を発生させる技術はすでに使われているわ。","ENG":"Artificial dimensional rift generation is already a standard tech.","TWN":"人為製造次元裂縫的技術已經是通用技術了。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"그럼에도 여전히 다이브에 차원 함선을 사용하는 이유는 안정성 때문이지.","JPN":"それでも相変わらずダイブに次元艦船を使用しているのは、安定性のためよ。","ENG":"But the reason dimensional ships are still used is for their stability.","TWN":"即便如此，仍然在躍入中使用次元艦船的原因是因為其穩定性。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};